// modules/Problems/services/ProblemsService.js

const _ = require('lodash');
const db = require('../../db'); // assuming a db module for querying

/**
 * Fetch problems filtered by difficulty, limit, and skill tags.
 * Skill tags filter is case-insensitive and can be comma-separated string or array.
 * The returned metadata includes normalized skill tags used for filtering.
 *
 * @param {Object} params
 * @param {number} [params.difficulty] - optional difficulty filter
 * @param {number} [params.limit=50] - max number of problems to return
 * @param {string|string[]} [params.skillTags] - skill tags filter (case-insensitive)
 * @returns {Promise<{problems: Array, metadata: Object}>}
 */
async function getProblems({ difficulty, limit = 50, skillTags } = {}) {
  // Normalize skillTags to array of lowercase strings
  let normalizedTags = [];
  if (skillTags) {
    if (Array.isArray(skillTags)) {
      normalizedTags = skillTags
        .filter(t => typeof t === 'string' && t.trim().length > 0)
        .map(t => t.trim().toLowerCase());
    } else if (typeof skillTags === 'string') {
      normalizedTags = skillTags
        .split(',')
        .map(t => t.trim().toLowerCase())
        .filter(t => t.length > 0);
    }
    // Remove duplicates
    normalizedTags = _.uniq(normalizedTags);
  }

  // Build base query
  // Assuming problems table has columns: id, name, difficulty, skill_tags (array of strings)
  // skill_tags stored normalized (lowercase)
  // We want stable sorting by id ascending

  // Using parameterized queries to prevent injection
  // We will build SQL dynamically depending on filters

  const params = [];
  let whereClauses = [];
  let idx = 1;

  if (typeof difficulty === 'number') {
    whereClauses.push(`difficulty = $${idx++}`);
    params.push(difficulty);
  }

  if (normalizedTags.length > 0) {
    // We want problems that have ALL the skill tags in normalizedTags
    // Assuming skill_tags is a text[] column, we can use @> operator in Postgres
    // skill_tags @> ARRAY[normalizedTags]
    whereClauses.push(`skill_tags @> $${idx++}::text[]`);
    params.push(normalizedTags);
  }

  const whereSQL = whereClauses.length > 0 ? `WHERE ${whereClauses.join(' AND ')}` : '';

  const limitSQL = `LIMIT $${idx++}`;
  params.push(limit);

  const sql = `
    SELECT id, name, difficulty, skill_tags
    FROM problems
    ${whereSQL}
    ORDER BY id ASC
    ${limitSQL}
  `;

  const { rows } = await db.query(sql, params);

  // Compose metadata with normalized skill tags used for filtering
  const metadata = {
    filters: {
      difficulty: typeof difficulty === 'number' ? difficulty : null,
      skillTags: normalizedTags.length > 0 ? normalizedTags : null,
      limit,
    },
    totalReturned: rows.length,
  };

  return {
    problems: rows,
    metadata,
  };
}

module.exports = {
  getProblems,
};
